        errors.append(error("username", "unsafe_chars", "Username contains unsafe characters."))
    if not USERNAME_RE.fullmatch(username):
        errors.append(error("username", "format", "Username must start with a letter and use lowercase letters, numbers, or underscores."))
    if "__" in username:
        errors.append(error("username", "repeated_separator", "Username cannot contain repeated underscores."))
    if username in RESERVED_USERNAMES or re.fullmatch(r"(admin|root|support|security|staff|system)\d*", username):
        errors.append(error("username", "reserved", "Username is reserved."))
    if any(term in username for term in BANNED_USERNAME_TERMS):
        errors.append(error("username", "blocked_term", "Username is not allowed."))

    return username, username, errors


def validate_display_name(raw: Any) -> tuple[str | None, list[dict[str, str]]]:
    errors = []
    if not isinstance(raw, str):
        return None, [error("display_name", "type", "Display name must be a string.")]

    value = normalize_text(raw)
    if not value:
        errors.append(error("display_name", "required", "Display name is required."))
    if len(value) < 1 or len(value) > 80:
        errors.append(error("display_name", "length", "Display name must be 1 to 80 characters."))
    if has_control_or_hidden_chars(value):
        errors.append(error("display_name", "unsafe_chars", "Display name contains unsafe characters."))
    if "<" in value or ">" in value:
        errors.append(error("display_name", "html", "Display name cannot contain HTML."))
    if re.search(r"https?://|www\.", value, re.I):
        errors.append(error("display_name", "url", "Display name cannot contain URLs."))

    return sanitize_display_name(value), errors


def breached_password(password: str) -> bool:
    if not CHECK_BREACHED_PASSWORDS:
        return False
    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]
    try:
        r = requests.get(f"https://api.pwnedpasswords.com/range/{prefix}", timeout=2.5)
        if r.status_code != 200:
            return False
        for line in r.text.splitlines():
            seen_suffix = line.split(":", 1)[0]
            if hmac.compare_digest(seen_suffix, suffix):
                return True
    except requests.RequestException:
        return False
    return False


def validate_password(raw: Any, username: str | None, email: str | None, display_name: str | None) -> tuple[str | None, list[dict[str, str]]]:
    errors = []
    if not isinstance(raw, str):
        return None, [error("password", "type", "Password must be a string.")]

    password = unicodedata.normalize("NFKC", raw)

    if len(password) < 12:
        errors.append(error("password", "too_short", "Password must be at least 12 characters."))
    if len(password) > 128 or len(password.encode("utf-8")) > 512:
        errors.append(error("password", "too_long", "Password is too long."))
    if has_control_or_hidden_chars(password) or "\x00" in password:
        errors.append(error("password", "unsafe_chars", "Password contains unsafe characters."))

    categories = [
        any(c.islower() for c in password),
        any(c.isupper() for c in password),
        any(c.isdigit() for c in password),
        any(not c.isalnum() and not c.isspace() for c in password),
    ]
    if sum(categories) < 3:
        errors.append(error("password", "complexity", "Password must include at least three of: lowercase, uppercase, number, symbol."))

    low = password.lower()
    if low in COMMON_PASSWORDS:
        errors.append(error("password", "common", "Password is too common."))
    if re.search(r"(.)\1{3,}", password):
        errors.append(error("password", "repeated", "Password contains too many repeated characters."))
    if any(seq in low for seq in ["123456789", "abcdef", "qwerty", "password", "letmein"]):
        errors.append(error("password", "sequence", "Password contains a common sequence."))
    if re.search(r"(19|20)\d{2}", password):
        errors.append(error("password", "year", "Password should not contain obvious years."))

    email_local = email.split("@", 1)[0] if email and "@" in email else ""
    for label, value in [("username", username), ("email", email_local), ("display name", display_name)]:
        if value and too_similar(password, html.unescape(value)):
            errors.append(error("password", "similarity", f"Password is too similar to your {label}."))

    if not errors and breached_password(password):
        errors.append(error("password", "breached", "Password appears in known data breaches."))

    return password, errors


@contextmanager
def db():
    conn = sqlite3.connect(DB_PATH, timeout=10)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA foreign_keys = ON")
    conn.execute("PRAGMA busy_timeout = 5000")
    try:
        yield conn
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


def init_db() -> None:
    with db() as conn:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                email_display TEXT NOT NULL,
                email_canonical TEXT NOT NULL UNIQUE,
                email_domain_ascii TEXT NOT NULL,
                username TEXT NOT NULL,
                username_canonical TEXT NOT NULL UNIQUE,
                display_name TEXT NOT NULL,
                password_hash TEXT NOT NULL,
                status TEXT NOT NULL DEFAULT 'pending_verification',
                created_at TEXT NOT NULL
            )
        """)
        conn.execute("CREATE INDEX IF NOT EXISTS idx_users_email_domain ON users(email_domain_ascii)")


@app.on_event("startup")
def startup() -> None:
    init_db()


@app.middleware("http")
async def security_headers(request: Request, call_next):
    response = await call_next(request)
    response.headers["X-Content-Type-Options"] = "nosniff"
    response.headers["X-Frame-Options"] = "DENY"
    response.headers["Referrer-Policy"] = "no-referrer"
    response.headers["Cache-Control"] = "no-store"
    response.headers["Content-Security-Policy"] = "default-src 'none'; frame-ancestors 'none'"
    return response


def validate_csrf_and_origin(request: Request) -> list[dict[str, str]]:
    errors = []
    origin = request.headers.get("origin")
    if origin and ALLOWED_ORIGINS and origin not in ALLOWED_ORIGINS:
        errors.append(error("request", "bad_origin", "Request origin is not allowed."))

    if request.headers.get("cookie"):
        csrf_cookie = request.cookies.get("__Host-csrf")
        csrf_header = request.headers.get("x-csrf-token")
        if not csrf_cookie or not csrf_header or not hmac.compare_digest(csrf_cookie, csrf_header):
            errors.append(error("request", "csrf", "CSRF validation failed."))
    return errors


@app.post("/api/register")
async def register(request: Request):
    ip = client_ip(request)
    retry = rate_limiter.check(f"register:ip:{ip}:minute", 5, 60)
    retry = retry or rate_limiter.check(f"register:ip:{ip}:hour", 20, 3600)
    if retry:
        return JSONResponse(
            {"ok": False, "errors": [error("request", "rate_limited", "Too many registration attempts.")]},
            status_code=429,
            headers={"Retry-After": str(retry)},
        )

    content_type = request.headers.get("content-type", "").split(";")[0].lower()
    if content_type != "application/json":
        return structured_errors([error("request", "content_type", "Content-Type must be application/json.")], 415)

    csrf_errors = validate_csrf_and_origin(request)
    if csrf_errors:
        return structured_errors(csrf_errors, 403)

    try:
        payload = await request.json()
    except Exception:
        return structured_errors([error("request", "json", "Malformed JSON body.")], 400)

    if not isinstance(payload, dict):
        return structured_errors([error("request", "body", "JSON body must be an object.")], 400)

    allowed = {"email", "username", "password", "display_name"}
    errors = [
        error("request", "unknown_field", f"Unknown field: {k}.")
        for k in payload.keys() - allowed
    ]

    email_display, email_canonical, email_domain, email_errors = validate_email_input(payload.get("email"))
    username, username_canonical, username_errors = validate_username(payload.get("username"))
    display_name, display_errors = validate_display_name(payload.get("display_name"))
    password, password_errors = validate_password(payload.get("password"), username, email_canonical, display_name)

    errors.extend(email_errors + username_errors + display_errors + password_errors)

    if email_canonical:
        email_key = hashlib.sha256(email_canonical.encode()).hexdigest()
        retry = rate_limiter.check(f"register:email:{email_key}", 3, 3600)
        if retry:
            return JSONResponse(
                {"ok": False, "errors": [error("request", "rate_limited", "Too many registration attempts.")]},
                status_code=429,
                headers={"Retry-After": str(retry)},
            )

    if errors:
        return structured_errors(errors, 422)

    password_hash = ph.hash(password)
    generic_response = {
        "ok": True,
        "message": "If registration can be completed, you will receive a confirmation email.",
        "request_id": secrets.token_urlsafe(16),
    }

    try:
        with db() as conn:
            conn.execute(
                """
                INSERT INTO users (
                    email_display, email_canonical, email_domain_ascii,
                    username, username_canonical, display_name,
                    password_hash, status, created_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    email_display,
                    email_canonical,
                    email_domain,
                    username,
                    username_canonical,
                    display_name,
                    password_hash,
                    "pending_verification",
                    now_iso(),
                ),
            )
    except sqlite3.IntegrityError:
        # Account enumeration prevention: same status/body for duplicate email or username.
        pass

    return JSONResponse(generic_response, status_code=202)
